    always @(*) begin
        case(in)
            3'b000: begin
                O0 = 1;
                O1 = 0;
                O2 = 0;
                O3 = 0;
                O4 = 0;
                O5 = 0;
                O6 = 0;
                O7 = 0;
            end
            3'b001: begin
                O0 = 0;
                O1 = 1;
                O2 = 0;
                O3 = 0;
                O4 = 0;
                O5 = 0;
                O6 = 0;
                O7 = 0;
            end
            3'b010: begin
                O0 = 0;
                O1 = 0;
                O2 = 1;
                O3 = 0;
                O4 = 0;
                O5 = 0;
                O6 = 0;
                O7 = 0;
            end
            3'b011: begin
                O0 = 0;
                O1 = 0;
                O2 = 0;
                O3 = 1;
                O4 = 0;
                O5 = 0;
                O6 = 0;
                O7 = 0;
            end
            3'b100: begin
                O0 = 0;
                O1 = 0;
                O2 = 0;
                O3 = 0;
                O4 = 1;
                O5 = 0;
                O6 = 0;
                O7 = 0;
            end
            3'b101: begin
                O0 = 0;
                O1 = 0;
                O2 = 0;
                O3 = 0;
                O4 = 0;
                O5 = 1;
                O6 = 0;
                O7 = 0;
            end
            3'b110: begin
                O0 = 0;
                O1 = 0;
                O2 = 0;
                O3 = 0;
                O4 = 0;
                O5 = 0;
                O6 = 1;
                O7 = 0;
            end
