      AA = DD;
      DD = CC;
      CC = BB;
      BB = BB + (F << (j % 4 * 7 + 7)) | (F >> (32 - (j % 4 * 7 + 7)));
    end

    A = A + AA;
    B = B + BB;
    C = C + CC;
